// Define the function to validate the branch name
function validateBranchName(branchName) {
    // Use a regular expression to match the branch name pattern
    return /^[a-zA-Z][a-zA-Z0-9-]*$/.test(branchName);
}

solutions.python:
class Solution:
    def validateBranchName(self, branchName: str) -> bool:
        # Use a regular expression to match the branch name pattern
        import re
        return bool(re.match(r'^[a-zA-Z][a-zA-Z0-9-]*$', branchName))
